import os
import tarfile
from zipfile import ZipFile
import subprocess
import shutil

def backup_directory(dir_path, format):
    if not os.path.exists(dir_path):
        raise FileNotFoundError(f"Directory '{dir_path}' does not exist")

    if format == 'tar.gz':
        filename = f"{os.path.basename(dir_path)}.tar.gz"
        with tarfile.open(filename, "w:gz") as tar:
            tar.add(dir_path)
    elif format == 'tar.bz2':
        filename = f"{os.path.basename(dir_path)}.tar.bz2"
        with tarfile.open(filename, "w:bz2") as tar:
            tar.add(dir_path)
    elif format == 'zip':
        filename = f"{os.path.basename(dir_path)}.zip"
        with ZipFile(filename, 'w') as zip_file:
            shutil.copytree(dir_path, os.path.join(zip_file.namelist()[0], dir_path))
    elif format == '7z':
        filename = f"{os.path.basename(dir_path)}.7z"
        subprocess.run(["7z", "a", filename, dir_path])
    else:
        raise ValueError(f"Unsupported compression format: {format}")

    print(f"Backup created at: {filename}")